class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int numberOfWays(int n, int x, int y) {
        long res = 1;
        for (int i = 0; i < n; i++) {
            res = (res * x) % MOD;
        }
        res = (res * pow(y, x)) % MOD;
        return (int) res;
    }

    private long pow(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) {
                res = (res * a) % MOD;
            }
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }
}
